var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_VAL_NULL","text":{"KOREA":"엄청 덜컹거리네. 헤스티아까지 있으면 비좁았겠어.","JPN":"めちゃくちゃ揺れる。ヘスティアまでいたら狭かったかも。","ENG":"It's really bumpy. It would've been cramped with Hestia here too."},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":null,"R":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"AIS_DANMACHI_NULL_NULL","text":{"KOREA":"헤스티아\xA0님… 괜찮으시려나?","JPN":"ヘスティア様……大丈夫かな？","ENG":"Lady Hestia... Will she be okay?"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"AIS_DANMACHI_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"RYU_DANMACHI_NULL_NULL","text":{"KOREA":"무슨 일이 벌어질지 모르는 이상, 가게에 남아 있는 편이 헤스티아\xA0님도 안전할 겁니다.","JPN":"何が起こるかわからない以上、店に残っていた方がヘスティア様も安全でしょう。","ENG":"Considering we don't know what might happen, staying at the shop is the safest option for Lady Hestia."},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"AIS_DANMACHI_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_VAL_NULL","text":{"KOREA":"그건 그렇다 쳐도… 성에 가는데 바니걸이 아니어도 돼?","JPN":"それはそうだけど……城に行くのにバニーガールじゃなくていいのか？","ENG":"That aside... is it really okay to head to the castle without wearing a bunny girl costume?"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"AIS_DANMACHI_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"RYU_DANMACHI_NULL_NULL","text":{"KOREA":"그것도 걱정 마시죠. 전후 변화가 중요하다며 만찬회가 시작되기 전까지 입을 평상복을 허락받았습니다.","JPN":"それも問題ありません。前後の変化が重要だからと、晩餐会が始まる前までは普段着を着ることを許可してくれました。","ENG":"Don't worry about that either. I was allowed to wear a set of casual clothes before the banquet, because of the importance of a before-and-after transformation."},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"AIS_DANMACHI_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"RYU_DANMACHI_NULL_NULL","text":{"KOREA":"그것보다 조용히. 성문 앞이에요.","JPN":"それより静かに。城門の前です。","ENG":"More importantly, quiet down. We're at the castle gate."},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"AIS_DANMACHI_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"KEEPER_NPC_DANMACHI_NULL","text":{"KOREA":"확인했습니다. 오늘 만찬회를 담당하실 류\xA0셰프님이시군요.","JPN":"確認しました。今日の晩餐会を担当するリューシェフですね。","ENG":"Understood. You must be Chef Ryu, the one in charge of today's banquet."},"stage":{"bg":"CORRIDOR_10","slots":{"L":null,"C":{"char_id":"KEEPER_NPC_DANMACHI_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KEEPER_NPC_DANMACHI_NULL","text":{"KOREA":"실례지만 수레 안을 확인해도 괜찮겠습니까?","JPN":"失礼ですが、荷車の中を確認してもいいですか？","ENG":"Excuse me, but may I check the contents of the cart?"},"stage":{"bg":"CORRIDOR_10","slots":{"L":null,"C":{"char_id":"KEEPER_NPC_DANMACHI_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RYU_DANMACHI_NULL_NULL","text":{"KOREA":"문제없습니다. 확인하시죠.\xA0","JPN":"問題ありません。","ENG":"No problem. Please go ahead."},"stage":{"bg":"CORRIDOR_10","slots":{"L":null,"C":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RYU_DANMACHI_NULL_NULL","text":{"KOREA":"……숨겨진 공간은 자연스럽게 보이도록 주변을 가려놨다.","JPN":"……隠れるためのスペースは自然に見えるように周りを覆っておいた。","ENG":"...The hidden space has been concealed to blend in naturally with the surroundings."},"stage":{"bg":"CORRIDOR_10","slots":{"L":null,"C":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RYU_DANMACHI_NULL_NULL","text":{"KOREA":"사전에는 바니걸 옷을 수납할 공간이라 말해 놨으니, 저쪽도 크게 의심하지는 않을 터.","JPN":"事前にバニーガールの服を入れておくスペースだと話しておいたから、そんなには疑わないはず。","ENG":"I told them in advance it's a storage space for bunny girl costumes, so they shouldn't be too suspicious."},"stage":{"bg":"CORRIDOR_10","slots":{"L":null,"C":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KEEPER_NPC_DANMACHI_NULL","text":{"KOREA":"음? 여기 나무가 썩어서 조그만 틈이 생겼군요.","JPN":"うん？　ここ、傷んで少し隙間ができていますね。","ENG":"Hmm? Looks like the wood here has decayed, leaving a tiny gap."},"stage":{"bg":"CORRIDOR_10","slots":{"L":null,"C":{"char_id":"KEEPER_NPC_DANMACHI_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KEEPER_NPC_DANMACHI_NULL","text":{"KOREA":"이건…….","JPN":"これは……","ENG":"This is..."},"stage":{"bg":"CORRIDOR_10","slots":{"L":null,"C":{"char_id":"KEEPER_NPC_DANMACHI_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RYU_DANMACHI_NULL_NULL","text":{"KOREA":"문제없습니다. 이런 빈티지함이 저희 가게에서 추구하는 미인지라!","JPN":"問題ありません。このようなヴィンテージさが私たちの店が追及している美ですので！","ENG":"No problem at all. This kind of vintage charm is exactly what our shop strives for!"},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KEEPER_NPC_DANMACHI_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"KEEPER_NPC_DANMACHI_NULL","text":{"KOREA":"아… 마음은 이해하지만, 저희 입장도 입장이라서요.","JPN":"ああ……気持ちはわかりますが、こちらの立場もあります。","ENG":"Ah... I understand your point, but we have our own concerns to consider."},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KEEPER_NPC_DANMACHI_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"KEEPER_NPC_DANMACHI_NULL","text":{"KOREA":"수레가 망가져 재료가 쏟아지기라도 하면, 오늘 만찬회에 영향이 가는지라…….","JPN":"荷車が壊れて材料が地面に転がると、今日の晩餐会に影響しますから……","ENG":"If the cart were to break and spill the supplies, it could affect today's banquet..."},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KEEPER_NPC_DANMACHI_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"KEEPER_NPC_DANMACHI_NULL","text":{"KOREA":"재료라면 저희 쪽 장비로 신선도를 유지할 테니 너무 걱정하실 필요 없습니다.","JPN":"材料なら私たちの装備で鮮度を維持しますので、あまり心配しないでください。","ENG":"The freshness of the ingredients will be maintained by our equipment, so there's no need to worry too much."},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KEEPER_NPC_DANMACHI_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"RYU_DANMACHI_NULL_NULL","text":{"KOREA":"……그게 아니라, 안에 든 식재료가 살아있어서 그렇습니다.","JPN":"……それが、中に入っている食材は生きているのです。","ENG":"...That's not the issue. It's because the ingredient inside is alive."},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KEEPER_NPC_DANMACHI_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"KEEPER_NPC_DANMACHI_NULL","text":{"KOREA":"사, 살아있다고요? 대체 어떤 재료길래…?","JPN":"い、生きているんですか？　いったいどんな材料を……？","ENG":"A-alive? What kind of ingredient are we talking about...?"},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KEEPER_NPC_DANMACHI_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"RYU_DANMACHI_NULL_NULL","text":{"KOREA":"네, 그건…….","JPN":"はい、それは……","ENG":"Uh, that's actually..."},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KEEPER_NPC_DANMACHI_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RYU_DANMACHI_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"..."},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KEEPER_NPC_DANMACHI_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"RYU_DANMACHI_NULL_NULL","text":{"KOREA":"토끼입니다!!","JPN":"ウサギです！！","ENG":"A bunny!!"},"stage":{"bg":"CORRIDOR_10","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KEEPER_NPC_DANMACHI_NULL","text":{"KOREA":"토, 토끼요……?","JPN":"う、ウサギですか……？","ENG":"B-bunny...?"},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KEEPER_NPC_DANMACHI_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"RYU_DANMACHI_NULL_NULL","text":{"KOREA":"네. 산지직송 마신님의 취향을 고려한 질 좋은 토끼입니다! 저희 가게에서 엄선한 특별 재료지요!","JPN":"はい。産地直送、マジン様の趣向を考えた上質なウサギです！　私のお店で厳選した特別な素材なのです！","ENG":"Yes, it's a high-quality bunny, freshly delivered from the source to match the tastes of Machination G.A.P.! It's a specially selected ingredient from our shop."},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KEEPER_NPC_DANMACHI_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_VAL_NULL","text":{"KOREA":"야, 너 갑자기 무슨……?","JPN":"ちょっと、いきなり何……？","ENG":"Hey, what are you suddenly talking about...?"},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"RYU_DANMACHI_NULL_NULL","text":{"KOREA":"토끼면 토끼답게 울란 말이다!","JPN":"ウサギはウサギらしく鳴きなさい！","ENG":"Act like a proper bunny and make bunny sounds!"},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_VAL_NULL","text":{"KOREA":"그러니까 대체 무슨 소리냐고?!","JPN":"いきなりなんだよ？","ENG":"What's that supposed to mean?!"},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"RYU_DANMACHI_NULL_NULL","text":{"KOREA":"맞춰 주시죠, 미나 씨. 이번만 넘긴다면 조용히 넘어갈 수 있을 겁니다.","JPN":"合わせてください、ミナさん。この場さえしのげたら、後は何ごともなく済ませられるはずです。","ENG":"Play along, Miss Mina. If we can get through this, we'll be in the clear."},"stage":{"bg":"CORRIDOR_10","slots":{"L":null,"C":null,"R":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_VAL_NULL","text":{"KOREA":"말이 되는 소리를 해…! 바니걸 복장이라고 진짜 토끼라 생각하는 사람이 어딨어?","JPN":"ふざけないで……！　バニーガールの服装だからって本物のウサギだと思う人はいないんだよ！","ENG":"Say something that makes sense...! Who would actually believe someone in a bunny girl costume is a real bunny?"},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"RYU_DANMACHI_NULL_NULL","text":{"KOREA":"미나 씨도 알고 계시겠지만 이곳은 정신적 영향력이 극대화되는 심상공간.","JPN":"ミナさんもご存じのとおり、ここは精神への影響力が極大化する心象空間。","ENG":"Miss Mina, as you're aware, this is a place of imagination where mental influences are maximized."},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"RYU_DANMACHI_NULL_NULL","text":{"KOREA":"즉, 자신을 토끼라고 믿으면… 미나 씨는 토끼가 되는 겁니다!","JPN":"つまり、自分がウサギだと信じれば……ミナさんはウサギになるのです！","ENG":"In other words, if you believe you're a bunny... Miss Mina, you'll become a bunny!"},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};